using System.Runtime.InteropServices;

partial class EnvVarCheck
{
    // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
    // env vars on Linux. Use native getenv to distinguish "not set" from "empty".
    [LibraryImport("libc", StringMarshalling = StringMarshalling.Utf8)]
    private static partial IntPtr getenv(string name);

    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        IntPtr ptr = getenv("MY_FLAG");
        if (ptr == IntPtr.Zero)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else
        {
            var val = Marshal.PtrToStringUTF8(ptr);
            // val is "" for explicitly empty, preserving the distinction
        }
    }
}

